{
  "name": "PACE (Program of All-Inclusive Care for the Elderly)",
  "eligibility": {
    "age": 65,
    "income_limits": "Based on previous calendar year's gross income. PACE: Single person ≤ $14,500; Married couple ≤ $17,700. Note: Search results describe Pennsylvania's Pharmaceutical Assistance Contract for the Elderly (PACE/PACENET), a prescription drug program, not the national PACE long-term care program. No asset limits apply; assets are not counted. Income includes gross Social Security (excluding Medicare premiums), pensions, wages, etc. Excludes: Property Tax/Rent Rebates, VA Aid and Attendance, SNAP, LIHEAP, first $10,000 death benefits, federal stimulus.[1][3][4][6][7]",
    "asset_limits": "No asset limits; assets are not counted.[7]",
    "other_requirements": [
      "Pennsylvania resident for at least 90 consecutive days prior to application.[1][3][4]",
      "Not eligible for or enrolled in Medicaid prescription benefits (Department of Human Services' Medical Assistance pharmaceutical benefits).[1][3][4]",
      "For national PACE long-term care (distinct program): 55+, live in service area, certified for nursing home level of care, able to live safely in community with PACE services; no income/asset test federally, but PA may differ. No PA-specific PACE long-term care details in results.[2]"
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Low-cost prescription drugs. PACE: $0 monthly premium; co-pays $6 generic, $9 brand-name per Rx. (PACENET, related: $37.45 monthly premium; $8 generic, $15 brand-name.) Funded by PA Lottery.[6][8]",
    "varies_by": "fixed"
  },
  "application": {
    "methods": [
      "Phone: PACE hotline 1-800-225-7223; PA MEDI helpline 1-800-783-7067.[5]",
      "Website: https://pacecares.magellanhealth.com/.[5]",
      "PA MEDI (local assistance for application).[5]"
    ],
    "processing_time": "Not specified in results.",
    "waitlist": null,
    "forms": ["Not specified; apply via hotline or website.[5]"],
    "documents": [
      "Proof of previous year's income (e.g., Social Security statements, tax returns, 1099s for pensions, wages, etc.).[7]",
      "Age, residency, and non-Medicaid verification.[7]"
    ]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Pennsylvania residents only.[1][3][4]",
    "regional_variations": "Administered statewide by PA Department of Aging; local PA MEDI programs for assistance, but no wait time or provider differences noted.[5]",
    "offices_or_providers": ["Statewide via Department of Aging; local PA MEDI sites.[5][8]"]
  },
  "official_source": "https://www.pa.gov/agencies/aging/aging-programs-and-services/pace-program[8]",
  "gotchas": [
    "This is Pennsylvania's PACE prescription drug program (Pharmaceutical Assistance Contract for the Elderly), NOT the national PACE (Program of All-Inclusive Care for the Elderly) long-term care/medical services program. Families seeking comprehensive elderly care (adult day health, transportation, nursing) need to search for PA PACE providers separately (e.g., via National PACE Association).[2]",
    "Income based on prior calendar year; capital gains from home sale count if within 2 years.[7]",
    "Excludes Medicare Part B premiums from income count; full Medicaid disqualifies, but Medicare Savings Program help with Part B may still qualify.[5]",
    "No automatic annual income adjustments.[6]"
  ],
  "data_shape_notes": "PA PACE is a statewide prescription-only program with fixed income thresholds by marital status (single/couple only, no larger households); no assets test; distinct from national PACE long-term care model which has no federal income test and requires nursing-home level certification."
}

{
  "name": "LIHEAP (Low-Income Home Energy Assistance Program)",
  "eligibility": {
    "age": null,
    "income_limits": "Gross annual income at or below 150% of Federal Poverty Guidelines (effective February 1, 2026): 1: $23,940; 2: $32,460; 3: $40,980; 4: $49,500; 5: $58,020; 6: $66,540; 7: $75,060; 8: $83,580; 9: $92,100; 10: $100,620; add $8,520 per additional person. Includes all household members' income.[1][3][5]",
    "asset_limits": "No resource or asset limits. No specific items counted or exempt.[4]",
    "other_requirements": ["Must reside in Pennsylvania.", "Renters and homeowners eligible.", "No requirement to be on public assistance.", "No requirement for unpaid heating bills.", "U.S. citizenship not strictly required but additional documents may be needed if not a citizen.", "Social Security Numbers required for household members age 1+ (affidavit if not provided)."][1][2][3][4][5]
  },
  "benefits": {
    "type": "financial",
    "value": "One-time cash grant paid directly to utility provider to help with heating costs. Amount varies by household income, size, fuel type, housing type, and region; specific dollar amounts or tables not detailed in sources (e.g., 'Benefits Table' referenced but not provided). Crisis grants available for emergencies.[1][2][5]",
    "varies_by": "household_size|priority_tier|region"
  },
  "application": {
    "methods": ["Online: COMPASS at https://www.compass.state.pa.us/ (English, Spanish, Simplified Chinese, Arabic, Cambodian, Haitian Creole, Nepali, Russian, Vietnamese applications available).", "Paper: Download LIHEAP application from https://www.pa.gov/agencies/dhs/resources/liheap, mail or deliver to local county assistance office.", "In-person: Local County Assistance Office (locations via county list on PA DHS site).", "Phone: Call local county assistance office (specific numbers via county list)."][1][2][3],
    "processing_time": "Not specified in sources.",
    "waitlist": null,
    "forms": ["LIHEAP Application (English, Spanish, Simplified Chinese, Arabic, Cambodian, Haitian Creole, Nepali, Russian, Vietnamese versions)."][3],
    "documents": ["Recent bill from main heating source (electric/gas/utility).", "Proof of household income for each member (pay stubs, award letters, employer statements).", "Names, birthdates, Social Security Numbers for all household members.", "Additional if non-citizen, heat included in rent, or income below basic living needs costs."][1][2][4][5]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Apply in the county of residence.",
    "regional_variations": "Administered by local County Assistance Offices; potential differences in grant amounts, processing, providers, or wait times by county/region not detailed.",
    "offices_or_providers": ["Local County Assistance Offices (full list on PA DHS site)."][2][3]
  },
  "official_source": "https://www.pa.gov/agencies/dhs/resources/liheap",
  "gotchas": ["Must reapply every year; prior approval does not carry over.", "Program availability seasonal (e.g., extended through May 8, 2026; check current status).", "Income includes all household members (related/unrelated).", "Apply for LIHEAP before other funds like Dollar Energy Fund.", "No automatic qualification from public assistance or unpaid bills.", "SSN affidavit required if not provided for members age 1+."][1][2][4][5],
  "data_shape_notes": "Income limits scale by household size at 150% FPL; no asset test; county-administered with potential regional grant variations; annual reapplication required."
}

{
  "name": "Weatherization Assistance Program (WAP)",
  "eligibility": {
    "age": null,
    "income_limits": "Households must have income at or below 200% of the federal poverty level. Effective January 13, 2026: 1 person: $31,920; 4-person family: $66,000 (full table not exhaustively listed in sources but scales by household size, e.g., York County example: 1: $30,120; 2: $40,880; 3: $51,640; 4: $62,400; 5: $73,160; 6: $83,920; 7: $94,680; 8: $105,440; add $11,360 per additional person). Alternative qualifiers: received cash assistance under Title IV or Title XVI (SSI) in prior 12 months, or eligible under Assistance Act of 1981 if at least 125% poverty.[1][2][4][9]",
    "asset_limits": "No asset limits mentioned in sources.",
    "other_requirements": ["Pennsylvania resident", "Priority to elderly, disabled, families with children, high energy users", "Homeowners or renters (renters need landlord permission and rental agreement; for rentals, no less than 66% units eligible or agreement no rent increase/eviction for 18 months)", "Single-family homes, rowhomes, trailers (no multi-family homes)", "Property not previously served within 15 years in some areas", "Housing in need of energy efficiency improvements"][1][2][3][4][6][9]
  },
  "benefits": {
    "type": "service",
    "value": "Free weatherization services including: blower door air sealing; attic/wall/basement/crawlspace insulation and ventilation; heating system tune-up/modification/replacement; hot water pipe/duct wrapping; caulking/weather-stripping windows/doors; minor repairs/health-safety measures; furnace/hot water tank safety checks; refrigerator replacement; programmable thermostats; dryer duct replacement; CFL bulbs; in-home energy education. Services based on energy audit; no furnaces/hot water tanks covered in some areas.[1][3][4][6][9]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact local weatherization agency serving your county (find via https://dced.pa.gov/programs/weatherization-assistance-program-wap/)", "Statewide phone: 1-866-466-3972", "Philadelphia-specific: online via PHDC, phone 215-448-2160 (Mon-Thu 9am-4pm, Fri 9am-12pm), in-person 1234 Market St. 17th Floor Philadelphia", "County-specific providers (e.g., Erie County Housing Authority, York County Planning Commission)"][1][5][6][10]],
    "processing_time": "Not specified in sources.",
    "waitlist": "Likely due to priority system and funding limits, but not detailed.",
    "forms": ["No specific form names/numbers listed; applications via local provider intake"],
    "documents": ["Photo ID", "Deed or lease (renters)", "Current/previous year income docs for all household members (gross income)", "Recent utility bills (all pages)", "Bank account info (Philadelphia)", "Landlord permission/rental agreement (renters)"][3][4][6]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available statewide via county-based agencies; some counties like Erie specify 'County of Erie Only'.",
    "regional_variations": "Administered by local agencies per county (e.g., PHDC in Philadelphia with specific docs/hotline; Erie County Housing; York County Planning Commission). Services lists and docs may vary slightly; income tables approximate but consistent at 200% FPL.[1][3][4][6][9]",
    "offices_or_providers": ["Local county weatherization agencies (directory at dced.pa.gov)", "Philadelphia: PHDC 1234 Market St.", "Erie: Erie County Housing Authority", "York: York County Planning Commission"][1][4][6][9]
  },
  "official_source": "https://dced.pa.gov/programs/weatherization-assistance-program-wap/",
  "gotchas": ["Priority to elderly/disabled/children/high energy users—may affect wait times", "Renters need landlord permission and no-rent-hike agreement", "No multi-family homes; single-family/rowhomes/trailers only", "Home cannot have been served recently (e.g., every 15 years in Philly)", "Income is gross (pre-tax); must total all household sources", "Find your specific county provider—statewide but locally administered", "No re-service for previously weatherized homes"][1][3][4][6][9],
  "data_shape_notes": "County-administered with local providers; income at 200% FPL scales by household size; priority tiers; renters require landlord approval; services audit-based and free but one-time per period."
}

{
  "name": "SHIP (State Health Insurance Assistance Program)",
  "eligibility": {
    "age": null,
    "income_limits": "No specific income or asset limits; open to all Medicare beneficiaries, with priority support for people with limited incomes, Medicare beneficiaries under age 65 with disabilities, and individuals dually eligible for Medicare and Medicaid[6].",
    "asset_limits": "No asset limits or tests apply[6].",
    "other_requirements": ["Medicare beneficiary (or family/caregiver of one)", "Pennsylvania resident[7]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free one-on-one counseling, education, and assistance on Medicare options including Original Medicare (Parts A & B), Medicare Advantage (Part C), Medicare Prescription Drug Coverage (Part D), and Medicare Supplement (Medigap); help applying for low-income programs like Medicaid, Medicare Savings Programs, and Extra Help/Low Income Subsidy; outreach via presentations, enrollment events, health fairs; Senior Medicare Patrol (SMP) services to prevent, detect, and report Medicare fraud, errors, and abuse[6][8]. No dollar amounts, hours, or direct financial aid provided.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-783-7067[7]", "Website: Pennsylvania Medicare Education and Decision Insight (PA MEDI) program site (linked via shiphelp.org)[7]"],
    "processing_time": "No formal application or processing time; services provided upon contact via phone or local counselors[6][7].",
    "waitlist": null,
    "forms": ["No specific forms required; counselors assist directly[6]"],
    "documents": ["Medicare card, details on current coverage, income info if applying for low-income subsidies (counselors guide preparation)[6]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available to Pennsylvania Medicare beneficiaries statewide[7]",
    "regional_variations": "Delivered through a network of over 2,200 local sites nationwide, including Pennsylvania; local counselors via area agencies on aging, social services, senior housing, and hospitals may vary by location but services are standardized[6][8]. No specific regional wait times or differences noted.",
    "offices_or_providers": ["PA MEDI – Pennsylvania Medicare Education and Decision Insight (statewide contact); local sites via shiphelp.org[7]"]
  },
  "official_source": "https://www.shiphelp.org/ships/pennsylvania/ (PA SHIP via shiphelp.org); national: https://acl.gov/programs/connecting-people-services/state-health-insurance-assistance-program-ship[6][7]",
  "gotchas": ["Not health insurance or direct financial aid—only free counseling and education; does not provide healthcare services itself[6][8]", "Priority for low-income, disabled under 65, or dual eligibles, but open to all Medicare beneficiaries[6]", "Often confused with children's CHIP program in PA; SHIP is strictly for Medicare help[1][4][7]", "Requires contacting local counselors for personalized help; no online self-service application[7]"],
  "data_shape_notes": "no income/asset test; counseling-only service via statewide phone/website with local delivery network; priority tiers by need but universal access for Medicare beneficiaries"
}

{
  "name": "Senior Community Service Employment Program (SCSEP)",
  "eligibility": {
    "age": 55,
    "income_limits": "Household income no more than 125% of the federal poverty level. Exact dollar amounts vary annually and by household size; contact local provider for current table (e.g., for 2025, 125% FPL for 1-person household is approximately $19,563, for 2-person $26,429—confirm with provider as not specified in sources).[3][4]",
    "asset_limits": "No asset limits mentioned in sources.",
    "other_requirements": ["Unemployed", "Live in Pennsylvania (some providers restrict to specific counties like Philadelphia, Westmoreland, Adams/York)", "Authorized to work in the US (Philadelphia-specific)", "PA resident"][1][2][3][7]
  },
  "benefits": {
    "type": "employment",
    "value": "On-the-job training at community sites (senior centers, schools, hospitals, daycare); average 20 hours/week or 20 hours/week/40 hours every two weeks; paid stipend at highest of federal/state/local minimum wage; bridge to unsubsidized employment; employment assistance.",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Philadelphia: Online interest form at https://www.phila.gov/programs/senior-community-service-employment-program-scsep/ or call (215) 686-8450[1]", "Westmoreland: Call 724-925-4084[2]", "York/Adams: In-person at Crispus Attucks with documents[7]", "Statewide: pa.gov/services/aging/apply-for-the-senior-community-service-employment-program (general info, contact local)[3]", "Contact local grantee/provider for county-specific"],
    "processing_time": "Not specified.",
    "waitlist": "Not mentioned; may vary by region due to funding limits.",
    "forms": ["Philadelphia: Participant interest form[1]", "Other areas: Application completed in-person or by contact"],
    "documents": ["State/Federal picture ID", "Social Security card", "Income documentation (Social Security, unemployment, etc.) (York/Adams example; prepare similarly elsewhere)"][7]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered by local grantees; county-specific (e.g., Philadelphia only Philly residents[1], Westmoreland County[2], Adams/York[7])",
    "regional_variations": "Different providers/offices by county (e.g., Philadelphia city program, Westmoreland at westmoreland.edu, York at Crispus Attucks); contact info and exact process varies; potential differences in wait times/funding availability.",
    "offices_or_providers": ["Philadelphia: phila.gov, (215) 686-8450[1]", "Westmoreland: westmoreland.edu, 724-925-4084[2]", "York/Adams: crispusattucks.org[7]", "State info: pa.gov[3]"]
  },
  "official_source": "https://www.pa.gov/services/aging/apply-for-the-senior-community-service-employment-program[3]",
  "gotchas": ["Not statewide uniform—must contact county-specific provider; some limit to exact county (e.g., Philly residents only); income is household-based at 125% FPL (stricter than some programs); temporary training (avg 6 months), not permanent job; priority to veterans, over 65, disabled, rural, etc.[4]; funding delays possible[5]"],
  "data_shape_notes": "County-restricted providers with varying contact methods; no fixed income table or asset limits in sources (use 125% FPL); benefits hours/wage fixed federally but local admin varies"
}

{
