    "offices_or_providers": ["Pennsylvania SeniorLAW Helpline (statewide)", "SeniorLAW Center (Philadelphia-based admin)", "PA Legal Aid Network local programs", "County Area Agencies on Aging", "PALawHelp.org for county locator[1][4]"]
