  "data_shape_notes": "Decentralized statewide network via local legal aid programs with varying guidelines pegged to 125% FPL; no fixed income/asset tables; priority-based with regional providers and high unmet need"
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; services are free and available to all regardless of financial status.",
    "asset_limits": "No asset limits; no financial tests apply.",
    "other_requirements": ["Resident (or potential resident) of a long-term care facility in Pennsylvania such as nursing homes, assisted living facilities, personal care homes, domiciliary care homes, adult day care centers, or receiving long-term care services in their home.", "Complaint or concern related to quality of care, quality of life, rights, discharge/transfer, service disruption, finances, medications, staffing, dietary issues, or facility policies.", "Services also extend to friends, families, facility staff, or community members advocating on behalf of residents."]
  },
  "benefits": {
    "type": "advocacy",
