    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Contact local Area Agency on Aging (AAA) Ombudsman program or state office (specific numbers vary by county, e.g., Franklin County 717-299-7979[3], Montgomery County 610-278-1320[8], PCA Helpline for Philadelphia[4], Elder Abuse Hotline 1-800-734-2020[8])", "Email: Varies by county (e.g., Ombudsman@montgomerycountypa.gov[8])", "Mail: Pennsylvania State Long-term Care Ombudsman, 555 Walnut Street, 5th Floor, Harrisburg, PA 17101[9]", "In-person: Local AAA offices or facility visits by Ombudsmen", "State contact: Via pa.gov services page for statewide referral[7]"],
    "processing_time": "Not specified; Ombudsmen respond to complaints promptly through investigation and mediation, but no fixed timeline provided.",
    "waitlist": null,
    "forms": ["Volunteer Ombudsman Registration Form (PDF) for those interested in volunteering, available from local programs like Lancaster County[3]"],
    "documents": ["No specific documents required for requesting assistance; provide details of the complaint or concern. Resident permission needed before discussing with facility staff; power of attorney (POA) if resident cannot express wishes[3]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Services delivered through 52 local Area Agencies on Aging (AAA) covering all Pennsylvania counties; must contact local provider for the relevant county.",
    "regional_variations": "Administered locally by county AAAs with varying contact info, offices, and volunteer programs (e.g., SWPA AAA serves Greene/Fayette/Washington[1], Franklin County[2], Lancaster[3], Philadelphia PCA[4], Montgomery[8]); no differences in core services noted.",
    "offices_or_providers": ["Local Area Agencies on Aging (AAA); State office: Pennsylvania Department of Aging, 555 Walnut Street, 5th Floor, Harrisburg, PA 17101[9]"]
  },
  "official_source": "https://www.pa.gov/agencies/aging/aging-programs-and-services/advocacy-education-protection[6]",
  "gotchas": ["Not a direct service provider or financial aid program—focuses solely on advocacy and complaint resolution, not delivering care or benefits.", "Requires resident permission to intervene with facility staff; otherwise, provides education only[3].", "Contact local AAA for your county, not just state office, as services are regionally delivered.", "Open to families/friends but prioritizes resident's voice and consent.", "Free and confidential, but not for general elder abuse (use hotline 1-800-734-2020 for that)[8]."],
  "data_shape_notes": "no income test; advocacy-only (not financial/service benefits); delivered via 52 local AAAs with county-specific contacts; available to residents, families, staff, and community members"
}
